VALUES
  ('social-worker-moex-02661', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '針對政府近些年來推動脫貧方案，就社會工作者而言，下列有關實務操作的敘述何者錯誤？', '["有工作能力但未就業之低收入戶、新貧、近貧人口以及前述人員子女是脫貧行動三個優先適用對象", "透過共同參與，預防新貧、近貧人口進入低收入戶行列，促使已進入低收入戶行列人員及早脫離低收 入戶身分是脫貧行動的短期目標", "提升個體的能力，增進個體全面發展是脫貧行動的最終目的", "具體操作可經由清查工作、生產性服務、支持性服務彼此配套，以及妥適的資源管理達成"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02662', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會團體工作中，自助團體被視為是經由了解幫助相同經驗者建構另一因應變通方案，協助成員滿足 其特殊需求，對此學者Riessman提到自主團體明顯的特徵，下列何者錯誤？', '["非競爭、合作導向", "菁英導向並有科層化型態", "強調本土化、內在的", "經由幫助別人獲得接受他人幫助的態度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02663', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '近些年來，國內對於社會企業的推動極為積極和熱絡，對於社會工作者而言，社會企業也被視為解決並 處理弱勢者的經濟、就業及相關問題的一種新的組織型態，下列有關社會企業的定義何者錯誤？', '["社會企業是指一個致力於公共財，並以獲取利潤追求永續經營的組織", "經費來源除了有非營利組織的傳統經費來源，尚包括商業的營利收入以及商業的活動", "社會企業強調社會創新精神，兼容社會、經濟與政策三大目的，以解決身心障礙者與弱勢族群的失業 問題", "社會企業強調社會與經濟目標的融合，除偏重商業收益，補貼非營利組織的財政缺口也是一種新型態 的社會投資"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02664', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者在擔任災難管理時的志工督導或管理者時，其對於志工的動員與管理的工作，下列敘述何者 錯誤？', '["督導或管理者必須讓志工以有組織的方式進入災區", "督導或管理者必須引導志工與倖存者有相當程度的隔絕與脫離", "督導或管理者必須引導志工及其他工作者有適切的結合與互補", "督導或管理者必須隨時注意志工的工作狀況與情緒反應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02665', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '進步年代（Progressive Era）與睦鄰運動的價值觀念比較偏重於關注下列那一方面的問題？', '["行為問題", "認知問題", "社會結構問題", "文化問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02666', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作者應與身障者建立「充權」的專業關係，下列何者不適用於「充權」敘述？', '["案主自決的倫理原則是促進社會融合的先決條件，應該視身障者為專家", "應依據過去的服務紀錄來判斷身障者的需求，而非只是聽從身障者自己的想法", "擴大身障者在日常生活中的選擇機會，提供積極復健計畫以增加自主與獨立", "體會身障者被邊緣化與烙印的感受，協助其面對與家人和社區的社會互動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02667', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作理論中，有關問題解決學派的描述，下列何者錯誤？', '["特別關注於案主的理性能力和認知力量", "社會工作者和案主應該結成夥伴關係", "詳細地辨別、描述和量化問題", "特別適合用於反歧視的實務中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02668', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '睦鄰運動（Settlement House Movement）與慈善組織會社（Charity Organization Society）雖同為社會工作 的起源，但兩者的價值精神與意識形態是很不相同的。下列對兩者的敘述，何者錯誤？', '["兩者都深受宗教慈善救濟窮人的措施所影響，並以宣揚教義為最終目標", "兩者都致力於研究分析、試圖以科學的方法來解決傳統慈善無法處理的問題", "睦鄰運動將貧窮問題的理解從宗教與非經濟歸因，轉化到社會環境歸因", "慈善組織會社整合、協調資源的目的是避免資源重複浪費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02669', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的價值、知識與技術可分為「重視人」、「重視社會」、「重視專業行為」三方面。下列何者 不是社會工作專業所強調的價值與技術？', '["尊重多元性", "自我了解", "災變預測", "有效溝通"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02670', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '實踐「個人和政治權力的啟動，獲致感覺個人有能力和肯定自己的經驗，並進而能獲取機會、連結資源、 採取行動以對抗社會控制」等主張，最接近下列那一個社會工作理論觀點？', '["生態系統理論", "充權與倡導觀點", "心理及社會學派", "多元文化觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "97356d6439d3", "answer_pdf_sha1": "4196eb0700b5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
